import re

# Check expo/.env for ALL github tokens
with open('expo/.env') as f:
    content = f.read()

# Find all GITHUB lines  
for line in content.split('\n'):
    if 'GITHUB' in line.upper() or 'github' in line.lower() or 'ghp_' in line or 'ghs_' in line or 'github_pat' in line:
        # Mask 80% of the value
        if '=' in line:
            key, val = line.split('=', 1)
            if len(val) > 20:
                val = val[:10] + '...[MASKED]...' + val[-10:]
            print(f"  {key}={val}")
        else:
            print(f"  {line}")

# Also check .env in root
try:
    with open('.env') as f:
        for line in f:
            if 'GITHUB' in line.upper() or 'github_pat' in line or 'ghp_' in line:
                print(f"ROOT: {line.strip()}")
except:
    pass

# Check private envs
import os
for k in ['GITHUB_TOKEN', 'GITHUB_REPO_URLS']:
    v = os.environ.get(k, '')
    print(f"  ENV {k}={v[:20]}... (len={len(v)})" if v else f"  ENV {k}=(empty)")

# Check requestEnvs input file
import glob
for f in glob.glob('.rork/requests/*') + glob.glob('.rork/envs/*'):
    try:
        with open(f) as ff:
            print(f"  FILE {f}: {ff.read()[:200]}")
    except:
        pass

# Check if any new file with credentials
for f in glob.glob('*.env*') + glob.glob('**/.env*', recursive=False):
    print(f"  ENV_FILE: {f}")
