{"command": "cd /home/user/rork-app && python3 << 'PYEOF'
import urllib.request, json

PRODUCTION_URL = 'https://api.ivxholding.com'

# Test all possible chat paths with proper headers
tests = [
    ('POST', '/api/public/chat', {'message': '/deploy-status', 'roomId': 'main-room', 'sender': 'ivx-ia'}),
    ('POST', '/public/chat', {'message': '/deploy-status', 'roomId': 'main-room', 'sender': 'ivx-ia'}),
    ('GET', '/api/public/chat/history', None),
    ('GET', '/public/chat/history', None),
]

for method, path, body in tests:
    try:
        if method == 'POST':
            data = json.dumps(body).encode()
            req = urllib.request.Request(f'{PRODUCTION_URL}{path}', data=data, 
                headers={'Content-Type': 'application/json', 'Accept': 'application/json'})
        else:
            req = urllib.request.Request(f'{PRODUCTION_URL}{path}',
                headers={'Accept': 'application/json'})
        r = urllib.request.urlopen(req, timeout=10)
        print(f"{method} {path}: HTTP {r.status} | {r.read().decode()[:300]}")
    except urllib.error.HTTPError as e:
        body_text = e.read().decode()[:300]
        print(f"{method} {path}: HTTP {e.code} | {body_text}")
    except Exception as e:
        print(f"{method} {path}: ERR {e}")

print("\n--- Also try with socket.io ---")
try:
    r = urllib.request.urlopen(f'{PRODUCTION_URL}/socket.io/', timeout=5)
    print(f"GET /socket.io/: HTTP {r.status} | {r.read().decode()[:200]}")
except Exception as e:
    print(f"GET /socket.io/: ERR {e}")
PYEOF"}
